; This file is generated by scripts/build_smartport_rom.py
; Source of truth:
;   - 6502_SSC.CN00.S
;   - 6502_SMARTPORT.S
;   - 6502_SSC.CF00.S
;
; The Appletini SmartPort card uses the reference a2retronet SmartPort
; C800/CF00 flow and the real SSC CN00 slot page for slot 7. The only
; local glue below is for unsupported serial/Pascal entry points, which
; are redirected to RTS because Appletini implements the SmartPort path
; only.

SLOT = 7
SSC = 0


;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;
;                               ;
; APPLE II SSC FIRMWARE         ;
;                               ;
;   BY LARRY KENYON             ;
;                               ;
;    -JANUARY 1981-             ;;;;;;;;;;;;;;
;                                            ;
; (C) COPYRIGHT 1981 BY APPLE COMPUTER, INC. ;
;                                            ;
;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;
;                               ;
; VARIABLE DEFINITIONS          ;
;                               ;
;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;
;;;;;;;;;;;;;;;;;;
; ZERO PAGE EQUS ;
;;;;;;;;;;;;;;;;;;
LOC0 = $00
LOC1 = $01
CH = $24         ; CURSOR HORIZONTAL POSITION
SLOT16 = $26         ; SAVE $N0 TO FREE UP Y-REG
CHARACTER = $27       ; OUTPUT, SCREEN AND INPUT CHARS
BASL = $28         ; BASE SCREEN ADDRESS POINTER
ZPTEMP = $35         ; WORKHORSE TEMPORARY
ZPTMP1 = $2A         ; WHEN ZPTEMP ISN'T ENOUGH
ZPTMP2 = $2B         ; TEMPORARIES, TEMPORARIES!
CSWL = $36         ; CHAR OUT VECTOR
CSWH = $37
KSWL = $38         ; CHAR IN VECTOR
KSWH = $39
A1L = $3C         ; BATCH MOVE POINTER
RNDL = $4E         ; RANDOM NUMBER SEED
RNDH = $4F
;;;;;;;;;;;;;;;;;;;
; GENERAL EQUATES ;
;;;;;;;;;;;;;;;;;;;
STACK = $0100       ; SYSTEM STACK BLOCK
INBUFF = $0200       ; SYSTEM INPUT BUFFER
KBD = $C000       ; KEYBOARD INPUT
KBDSTRB = $C010       ; KEYBOARD CLEAR
ROMSOFF = $CFFF       ; DISABLES C0-RES. $C800 ROMS
;;;;;;;;;;;;;;;;;;;;;;
; SSC CARD ADDRESSES ;
;;;;;;;;;;;;;;;;;;;;;;
DIPSW1 = $C081       ; (+$N0) DIPSWITCH BLOCK 1
DIPSW2 = $C082       ; (+$N0) DIPSWITCH BLOCK 2
TDREG = $C088       ; (+$N0) TRANSMIT DATA REG (WRITE)
RDREG = $C088       ; (+$N0) READ DATA REG (READ)
STREG = $C089       ; (+$N0) STATUS REGISTER (READ)
RESET = $C089       ; (+$N0) SOFTWARE RESET (WRITE)
CMDREG = $C08A       ; (+$N0) COMMAND REGISTER (R/W)
CTLREG = $C08B       ; (+$N0) CONTROL REGISTER (R/W)
;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;
;  BIT-> B7  B6  B5  B4  B3  B2  B1  B0
;        +----------------------------+
; DIPSW1 S1  S2  S3  S4  Z   Z   S5  S6  (LEFT DIPSWITCH)
;
; (S1-S4 USED FOR BAUD RATE, S5-S6 FOR FIRMWARE MODE)
;
; DIPSW2 S1  Z   S2  Z   S3  S4  S5  CTS (RIGHT DIPSWITCH)
;
; STREG  INT DSR DCD TDR RDR OVR FE  PE
;
; CTLREG STB << WL >> CK << BAUD RATE >>
;
; CMDREG <<PARITY >> ECH <<XMIT>> RE DTR
;
;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;
;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;
; SCREEN VARIABLES: PPC AND SIC MODES ;
;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;
CMDBYTE = $5F8-$C0    ; HOLDS COMMAND CHARACTER (PPC & CIC)
HANDSHKE = $4F8-$C0   ; SIC P8A CHAR COUNTER FOR ETX/ACK
PARAMETER = $4F8-$C0  ; ACCUMULATOR FOR CMD PARAMETER
STATEFLG = $578-$C0
; B7=CR GEN ENB FLAG  B6=AFTER LC INPUT FLG
; B2-B0=COMMAND INTERPRETER STATES
;   0 0 0   IDLE
;   0 0 1   CMD CHAR RECEIVED
;   0 1 0   COLLECT <N> UNTIL CHAR THEN DO COMMAND
;   0 1 1   SKIP UNTIL SPACE, THEN GOTO STATE 4
;   1 0 0   E/D COMMANDS
;   1 0 1   UNUSED
;   1 1 0   WAIT UNTIL CR THEN SET STATE TO ZERO
;   1 1 1   WAIT UNTIL CR THEN DO PROC INDICATED BY PARM
;
; (B4-B0 DETERMINE ENQUIRE CHAR FOR P8A MODE)
;
DELAYFLG = $478-$C0
; B7-B6=SCREEN TRANSLATION OPTIONS
;  0 0   LC->UC
;  0 1   NO TRANSLATION
;  1 0   LC->UC INVERSE
;  1 1   LC->UC, UC->UC INVERSE
;  (1-3 WILL ALLOW LC CHARS TO PASS THRU MONITOR)
;
; B5-B4=CR DELAY    0 0 = NO DELAY
; B3-B2=LF DELAY    0 1 = 32 MILLISEC
; B1-BO=FF DELAY    1 0 = 1/4 SEC
;                   1 1 = 2 SEC
;
STSBYTE = $678-$C0    ; STATUS/IORESULT/INPUT BYTE
PWDBYTE = $6F8-$C0    ; PRINTER (FORMAT) WIDTH
COLBYTE = $778-$C0    ; COLUMN POSITION COUNTER
MISCFLG = $7F8-$C0
; B7=ECHO BIT       B6=TABBING OPTION ENABLE
; B5=LINEFEED EAT   B4=PASCAL/BASIC FLAG
; B3=XOFF ENB FLAG  B2=KEYBOARD ENB
; B1=PPC/CIC MODE   B0=LF GENERATE ENB
;
;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;
; TEMP SCREEN VARS (SLOT INDEPENDENT) ;
;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;
MSLOT = $7F8        ; BUFFER FOR HI SLOT ADDR (SCN)
;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;
; SCREEN VARIABLES: CIC MODE ;
;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;
;
; STATEFLG: B7=TERMINAL MODE FLAG
;        B3-B5=CHAIN SLOT
;
CHNBYTE = $6F8-$C0    ; CURRENT OUTPUT SCREEN ($CN00 ENTRY)
;
; B0-B7=CN00 ENTRY
;
BUFBYTE = $778-$C0    ; BUFFER FOR ONE
;                         INPUT BYTE: HIGH BIT IS SET
;                         WHEN BUFFER IS FULL
;
; MISCFLG: B6=TERM MODE SHIFT ENB
;
; OTHER SLOT VARIABLES AS DEFINED FOR PPC AND SIC MODES
;
;;;;;;;;;;;;;;;;;;;;;;;
; MONITOR SUBROUTINES ;
;;;;;;;;;;;;;;;;;;;;;;;
COUT = $FDED       ; CHARACTER OUT (THRU CSW)
SETKBD = $FE89       ; SETS KSW TO APPLE KEYBOARD
IORTS = $FF58       ; KNOWN "RTS" LOCATION
NXTA1 = $FCBA       ; INCREMENT A1H,L AND CMP TO A2H,L
SETSCR = $FE93       ; SETS CSW TO APPLE SCREEN
VIDOUT = $FDF6       ; OUTPUT A CHAR TO APPLE SCREEN
SLOOP = $FABA       ; CONTINUE SLOT SCAN
SETTXT = $FB39       ; SET TEXT MODE
HOME = $FC58       ; CLEAR SCREEN AND HOME CURSOR
PRERR = $FF2D       ; DISPLAY "ERR" AND BEEP
BASIC = $E000       ; BASIC INTERPRETER COLD START
BASCALC = $FBC1       ; CALC SCREEN BASE ADR IN BASH,L

;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;
;                               ;
; VARIABLE DEFINITIONS          ;
;                               ;
;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;
;;;;;;;;;;;;;;;;;;
; ZERO PAGE EQUS ;
;;;;;;;;;;;;;;;;;;
CMD = $42         ; PRODOS COMMAND
UNIT = $43         ; PRODOS UNIT
ADDRL = $44         ; PRODOS / SMARTPORT BUFFER ADDRESS
ADDRH = $45
BLOCKL = $46         ; PRODOS BLOCK
BLOCKH = $47
SIZEL = $46         ; SMARTPORT BUFFER SIZE
SIZEH = $47
;;;;;;;;;;;;;;;;;;;;;;;
; SMARTPORT ADDRESSES ;
;;;;;;;;;;;;;;;;;;;;;;;
DATA = $CFF0       ; SMARTPORT DATA REGISTER
CTRL = $CFF1       ; SMARTPORT CONTROL REGISTER
;;;;;;;;;;;;;;;;;;;;;;;;
; BASIC MODE ADDRESSES ;
;;;;;;;;;;;;;;;;;;;;;;;;
BENTER = $CFF9       ; ENTER A2RETRONET BASIC MODE
BLEAVE = $CFFA       ; LEAVE A2RETRONET BASIC MODE
;;;;;;;;;;;;;;;;;;;;;
; BANKING ADDRESSES ;
;;;;;;;;;;;;;;;;;;;;;
BANKCLR = $CFFB       ; CLEAR EXPANSION ROM BANK
BANKSET = $CFFC       ; SET EXPANSION ROM BANK


; Unsupported SSC serial/Pascal targets are intentionally stubbed.
BINIT = IORTS
PASCALINIT = IORTS
PASCALREAD = IORTS
PASCALWRITE = IORTS
PENTRY = IORTS
SROUT = IORTS
SRIN = IORTS
INIT1 = IORTS
BINPUT = IORTS
OUTPUT = IORTS
CICEXIT = IORTS
SEROUT = IORTS

; Real slot-7 CN00 page from the reference SSC source.

;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;
;                               ;
; APPLE II SSC FIRMWARE         ;
;                               ;
;   BY LARRY KENYON             ;
;                               ;
;    -JANUARY 1981-             ;;;;;;;;;;;;;;
;                                            ;
; (C) COPYRIGHT 1981 BY APPLE COMPUTER, INC. ;
;                                            ;
;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;
;                               ;
; CN00 SPACE CODE               ;
;                               ;
;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;

        .org $C000+$0100*SLOT


        CMP #$20        ; $CN01:$20
        CMP #$00        ; $CN03:$00
        CMP #$03        ; $CN05:$03
        CMP #$3C        ; $CN07:$3C; ROM builder patches this byte to $00
        CLV
        BVC DENTRY      ; <ALWAYS> SKIP AROUND PASCAL 1.1 ENTRY


        .byte $01         ; GENERIC SIGNATURE BYTE
        .byte $31         ; DEVICE SIGNATURE BYTE
        .byte <PINIT
        .byte <PREAD
        .byte <PWRITE
        .byte <PSTATUS

;;;;;;;;;;;;;;;;;;;
;                 ;
;  BASIC ENTRIES  ;
;                 ;
;;;;;;;;;;;;;;;;;;;

IENTRY: SEC             ; BASIC INPUT ENTRY
        .byte $90         ; OPCODE FOR BCC
OENTRY: CLC             ; BASIC OUTPUT ENTRY
        CLV

BENTRY: STA CHARACTER
        STX ZPTEMP      ; INPUT BUFFER INDEX
        TXA             ; SAVE X AND Y REGS ON STACK
        PHA
        TYA
        PHA
        JSR BSETUP
        JMP BINIT

;;;;;;;;;;;;;;;;;;;;;;;;;;;;
;                          ;
;  DISK INTERFACE ENTRIES  ;
;                          ;
;;;;;;;;;;;;;;;;;;;;;;;;;;;;

DISK: CLC             ; PRODOS DRIVER ENTRY
        BCC SETUP
        SEC             ; SMARTPORT DRIVER ENTRY
SETUP: JSR DSETUP
        JMP COMMON

DENTRY: JSR DSETUP
        JMP BOOT

;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;
;                                ;
;      PASCAL INTERFACE ENTRIES  ;
;                                ;
;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;
PINIT: JSR PASCALINIT
        LDX #0          ; NO ERROR POSSIBLE
        RTS
PREAD: JMP PASCALREAD
PWRITE: JMP PASCALWRITE
;
; PASCAL STATUS REQUEST
;
; A-REG=0 -> READY FOR OUTPUT?
; A-REG=1 -> HAS INPUT BEEN RECEIVED?
;
PSTATUS: LSR A           ; SAVE REQUEST TYPE IN CARRY
        JSR PENTRY      ; (PRESERVES CARRY)
        BCS PSTATIN
        JSR SROUT       ; READY FOR OUTPUT?
        BEQ PSTATUS2
        CLC
        BCC PSTATUS2    ; CARRY CLEAR EOR NOT READY

PSTATIN: JSR SRIN        ; SETS CARRY CORRECTLY
PSTATUS2: LDA STSBYTE,X  ; GET ERROR FLAGS
        TAX
        RTS

;;;;;;;;;;;;;;;;;;;;;;;;
; SHARED SETUP ROUTINE ;
;;;;;;;;;;;;;;;;;;;;;;;;
BSETUP: LDY #$10*SLOT   ; Y-REG WILL GENERALLY BE $N0
        STY SLOT16
DSETUP: LDX #$C0+SLOT   ; X-REG WILL GENERALLY BE $CN
        STX MSLOT
        STA ROMSOFF     ; SWITCH OUT OTHER $C800 ROMS
        RTS

;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;
; ROUTINE TO SEND A CHARACTER TO ANOTHER CARD ;
;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;
SENDCD: LDX #3
SAVEHOOK: LDA CSWL,x
        PHA
        DEX
        BPL SAVEHOOK
;
; PUT CARD ADDRESS IN HOOK
;
        LDX MSLOT
        LDA CHNBYTE,X
        STA CSWL
        LDA STATEFLG,X  ; GET SLOT #
        AND #$38
        LSR A
        LSR A
        LSR A
        ORA #$C0        ; FORM $CN
        STA CSWH
;
; OUTPUT TO THE PERIPHERAL
;
        LDA CHARACTER
        PHA
        ORA #$80        ; 80 COL BOARDS WANT HI-BIT ON
        JSR COUT
;
; RESTORE EVERYTHING THE OTHER CARD MAY HAVE CLOBBERED
;
        PLA
        STA CHARACTER
        JSR BSETUP
;
; PUT BACK CSWL INTO CHNBYTE
;
        LDA CSWL
        STA CHNBYTE,X

        LDX #0
RESTORHOOK: PLA
        STA CSWL,X
        INX
        CPX #4
        BCC RESTORHOOK

        LDX MSLOT
        RTS

        .res $0100-$10-<*

;;;;;;;;;;;;;;;;;;
;                ;
;  CONFIG ENTRY  ;
;                ;
;;;;;;;;;;;;;;;;;;

CONFIG: JSR DSETUP
        JMP CFG

        .byte $4F, $6C, $53, $63


        .byte $00
        .byte $00         ; SMARTPORT ID
        .byte $00,$00     ; TOTAL BLOCKS
        .byte $D7         ; STATUS BYTE


        .byte <DISK

; Reference SmartPort C800 flow.

