;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;
;                               ;
; C800 SPACE                    ;
;                               ;
;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;

        .org $C800

        .byte $00         ; B/C OF RTS OFFSET

;;;;;;;;;;;;;;;;;;;
; PRODOS COMMANDS ;
;;;;;;;;;;;;;;;;;;;
PDSTS: ; EXECUTE AND GET RETURN CODE
        JSR RETCODE
        BNE PDDONE      ; ERROR?

        LDX DATA        ; SIZE LO
        LDY DATA        ; SIZE HI
PDOKAY: LDA #$00        ; SUCCESS
PDDONE: CMP #$01        ; SUCCESS?
        JMP QUIT

PDRD: ; EXECUTE AND GET RETURN CODE
        JSR RETCODE
        BNE PDDONE      ; ERROR?

        ; READ BLOCK
        JSR RDBLK1
        JMP PDOKAY

PDWR: ; WRITE BLOCK
        JSR WRBLOCK

        ; EXECUTE AND GET RETURN CODE
        JSR RETCODE
        CMP #$01        ; SUCCESS?
        JMP QUIT

;;;;;;;;;;;;;;;;;;;;;;
; SMARTPORT COMMANDS ;
;;;;;;;;;;;;;;;;;;;;;;
STATUS: ; EXECUTE AND GET STATUS
        JSR GETSTS
        BNE RETURN      ; ERROR?

        ; READ STATUS LIST SIZE
        LDA DATA
        STA SIZEL
        LDA DATA
        STA SIZEH

        ; READ STATUS LIST
        LDY #$02        ; OFFSET OF STATUS LIST ADDRESS
        JSR SETADDR
        JSR RDBUF
        LDX SIZEL
        LDY SIZEH
        JMP RETURN

READBL: ; EXECUTE AND GET STATUS
        JSR GETSTS
        BNE RETURN      ; ERROR?

        ; READ BLOCK
        LDY #$02        ; OFFSET OF BUFFER ADDRESS
        JSR SETADDR
        JSR RDBLK1
        JMP RETURN

WRITEBL: ; WRITE BLOCK
        LDY #$02        ; OFFSET OF BUFFER ADDRESS
        JSR SETADDR
        JSR WRBLOCK
        ; FALL THROUGH

FORMAT: ; EXECUTE AND GET STATUS
        JSR GETSTS
        JMP RETURN

CONTROL: ; WRITE CONTROL LIST
        LDY #$02        ; OFFSET OF CONTROL LIST ADDRSS
        JSR SETADDR
        LDY #$00        ; OFFSET OF CONTROL LIST SIZE
        JSR SETSIZE
        LDA SIZEL
        CLC
        ADC #$02        ; ADD SIZE OF CONTROL LIST SIZE
        STA SIZEL
        BCC NOINC
        INC SIZEH
NOINC: JSR WRBUF
        ; FALL THROUGH

INIT: ; FALL THROUGH

OPEN: ; FALL THROUGH

CLOSE: ; EXECUTE AND GET STATUS
        JSR GETSTS
        JMP RETURN

READ: ; EXECUTE AND GET STATUS
        JSR GETSTS
        BNE RETURN      ; ERROR?

        ; READ BUFFER
        LDY #$04        ; OFFSET OF BYTE COUNT
        JSR SETSIZE
        LDY #$02        ; OFFSET OF BUFFER ADDRESS
        JSR SETADDR
        JSR RDBUF
        JMP RETURN

WRITE: ; WRITE BUFFER
        LDY #$04        ; OFFSET OF BYTE COUNT
        JSR SETSIZE
        LDY #$02        ; OFFSET OF BUFFER ADDRESS
        JSR SETADDR
        JSR WRBUF

        ; EXECUTE AND GET STATUS
        JSR GETSTS
        ; FALL THROUGH

RETURN: ; RESTORE ZEROPAGE LOCATIONS
        PLA
        STA ADDRL
        PLA
        STA ADDRH
        PLA
        STA SIZEL
        PLA
        STA SIZEH
        PLA             ; STATUS
        CMP #$01        ; SET CARRY
        JMP QUIT

;;;;;;;;;;;;;;;;;;
; HANDLER SWITCH ;
;;;;;;;;;;;;;;;;;;
SWITCH: BCC PRODOS
        JMP SMARTPORT

;;;;;;;;;;;;;;;;;;
; PRODOS HANDLER ;
;;;;;;;;;;;;;;;;;;
PRODOS: ; WRITE PARAMETERS
        LDX CMD
        STX DATA
        LDA UNIT
        STA DATA
        LDA ADDRL
        STA DATA
        LDA ADDRH
        STA DATA
        LDA BLOCKL
        STA DATA
        LDA BLOCKH
        STA DATA

        ; DISPATCH COMMAND
        LDA #>$C800
        PHA
        LDA PDCMD,X
        PHA
        RTS

PDCMD: .byte <PDSTS-1, <PDRD-1, <PDWR-1

;;;;;;;;;;;;;;;;;;;;;
; SMARTPORT HANDLER ;
;;;;;;;;;;;;;;;;;;;;;
SMARTPORT:
        ; SAVE ZEROPAGE LOCATIONS AND RESERVE STATUS SLOT
        TSX
        LDY #$04
SAVE: LDA ADDRL,Y
        PHA
        DEY
        BPL SAVE

        ; GET ADDRESS OF PARAMETERS AND ADJUST STACK
        CLC
        INX
        LDA $0100,X
        STA ADDRL
        ADC #<$0003     ; SIZE OF PARAMETERS
        STA $0100,X
        INX
        LDA $0100,X
        STA ADDRH
        ADC #>$0003     ; SIZE OF PARAMETERS
        STA $0100,X

        ; PREPARE COMMAND DISPATCH
        LDA #>$C800
        PHA
        LDY #$01+$00    ; PUSH OFFSET + OFFSET OF COMMAND NUMBER
        LDA (ADDRL),Y
        TAX
        LDA SPCMD,X
        PHA

        ; WRITE COMMAND NUMBER
        STX DATA

        ; GET COMMAND LIST ADDRESS
        LDY #$01+$01    ; PUSH OFFSET + OFFSET OF COMMAND LIST ADDRESS
        JSR SETADDR

        ; WRITE COMMAND LIST
        LDA #<$0009     ; SIZE OF LARGEST COMMAND LIST
        STA SIZEL
        LDA #>$0009     ; SIZE OF LARGEST COMMAND LIST
        STA SIZEH
        JSR WRBUF

        ; DISPATCH COMMAND
        RTS

SPCMD: .byte <STATUS-1, <READBL-1, <WRITEBL-1, <FORMAT-1, <CONTROL-1
        .byte <INIT  -1, <OPEN  -1, <CLOSE  -1, <READ  -1, <WRITE  -1

;;;;;;;;;
; UTILS ;
;;;;;;;;;
SETSIZE: ; SET 16-BIT BUFFER SIZE
        LDA (ADDRL),Y
        STA SIZEL
        INY
        LDA (ADDRL),Y
        STA SIZEH
        RTS

SETADDR: ; SET BUFFER ADDRESS
        LDA (ADDRL),Y
        TAX
        INY
        LDA (ADDRL),Y
        STA ADDRH
        STX ADDRL
        RTS

GETSTS: ; EXECUTE SMARTPORT COMMAND AND GET STATUS
        LDA #$02        ; SMARTPORT
        JSR WRCMD

        ; SAVE STATUS IN STACK SLOT
        TSX
        TAY
        TXA
        CLC
        ADC #$07        ; OFFSET OF STACK SLOT
        TAX
        TYA
        STA $0100,X
        RTS

RETCODE: ; EXECUTE PRODOS COMMAND AND GET RETURN CODE
        LDA #$01        ; PRODOS
        ; FALL THROUGH

WRCMD: ; WRITE COMMAND REG AND READ RESPONSE
        STA CTRL
WAIT: LDA CTRL
        BPL WAIT
        LDA DATA
        RTS

RDBUF: ; READ BUFFER
        LDY #$00
        LDX SIZEH
        BEQ RDREST
RDFULL: JSR RDPAGE
        INC ADDRH
        DEX
        BNE RDFULL
RDREST: LDX SIZEL
        BEQ RDDONE
RDMORE: LDA DATA
        STA (ADDRL),Y
        INY
        DEX
        BNE RDMORE
RDDONE: RTS

WRBUF: ; WRITE BUFFER
        LDY #$00
        LDX SIZEH
        BEQ WRREST
WRFULL: JSR WRPAGE
        INC ADDRH
        DEX
        BNE WRFULL
WRREST: LDX SIZEL
        BEQ WRDONE
WRMORE: LDA (ADDRL),Y
        STA DATA
        INY
        DEX
        BNE WRMORE
WRDONE: RTS

RDBLK1: ; READ 512-BYTE BLOCK (in-bank; CF00 RDBLOCK jumps here)
        LDY #$00
        JSR RDPAGE
        INC ADDRH
        JSR RDPAGE
        DEC ADDRH
        RTS
RDPAGE: LDA DATA
        STA (ADDRL),Y
        INY
        BNE RDPAGE
        RTS

WRBLOCK: ; WRITE 512-BYTE BLOCK
        LDY #$00
        JSR WRPAGE
        INC ADDRH
        JSR WRPAGE
        DEC ADDRH
        RTS
WRPAGE: LDA (ADDRL),Y
        STA DATA
        INY
        BNE WRPAGE
        RTS

;;;;;;;;;;;;;;;;
; BOOT HANDLER ;
;;;;;;;;;;;;;;;;
BOOT1: LDX #$FF
RETRY: LDA KBD
        BMI HAVEKEY
        INX
        STX DATA
        LDA #$40        ; CONFIG
        JSR WRCMD
        BNE DOBOOT
        LDA DATA
        STA $07F7
        BNE RETRY       ; ALWAYS
HAVEKEY: STA KBDSTRB
        CLV             ; NO ERROR TEXT
        CMP #'C'+$80
        BEQ DOCFG
        CMP #'c'+$80
        BEQ DOCFG
        CMP #'N'+$80
        BEQ DONE
        CMP #'n'+$80
        BEQ DONE
        CMP #'1'+$80
        BCC DOBOOT
        CMP #'9'+$80
        BCS DOBOOT
        LDY #$64        ; SET BOOT
        STY DATA
        STA DATA
        LDA #$40        ; CONFIG
        JSR WRCMD
        BEQ DOBOOT
        BNE RETRY       ; ALWAYS

DOCFG: JSR CFGHDLR

DOBOOT: LDX #$01
        STX CMD
        LDA MSLOT
        ASL
        ASL
        ASL
        ASL
        STA UNIT        ; DRIVE 1
        DEX
        STX ADDRL
        LDA #>$0800
        STA ADDRH
        STX BLOCKL
        STX BLOCKH
        JMP PDBOOT      ; CALL PRODOS HANDLER

BOOT2: BIT ERRTEXT     ; "SEV" -> ERROR TEXT
        BCS DONE
        LDX $0800       ; NUMBER OF DISK II SECTORS TO READ
        DEX
        BNE DONE        ; ... MUST BE 1
        LDA $0801       ; FIRST OPCODE
        BEQ DONE        ; ... MUSTN'T BE BRK
        LDA #>($0801-1)
        PHA
        LDA #<($0801-1)
        PHA
        LDX UNIT
        JMP QUIT        ; GO FOR IT

DONE: LDA LOC0        ; POTENTIAL AUTOSTART SCAN ROM PTR LO
        BNE EXIT        ; ... MUST POINT TO A SLOT ROM START
        LDA LOC1        ; POTENTIAL AUTOSTART SCAN ROM PTR HI
        CMP MSLOT
        BNE EXIT        ; ... MUST POINT TO CURRENT SLOT ROM
        LDA #>(SLOOP-1)
        PHA
        LDA #<(SLOOP-1)
        PHA
        JMP QUIT        ; LOOKS LIKE AUTOSTART SCAN SO CONTINUE SCAN

EXIT: PHP             ; SAVE V
        JSR SETSCR
        JSR SETKBD
        JSR SETTXT
        JSR HOME
        PLP             ; RESTORE V
        BVC COLD
        LDX #$08        ; 'HDD ERROR'
ERR: LDA ERRTEXT,X
        JSR COUT
        DEX
        BPL ERR
COLD: LDA #>(BASIC-1)
        PHA
        LDA #<(BASIC-1)
        PHA
        JMP QUIT

ERRTEXT: .byte 'R'|$80, 'O'|$80, 'R'|$80, 'R'|$80, 'E'|$80, ' '|$80, 'D'|$80, 'D'|$80, 'H'|$80

;;;;;;;;;;;;;;;;;;
; CONFIG HANDLER ;
;;;;;;;;;;;;;;;;;;
CFGHDLR: STA $C051       ; TEXT
        STA $C054       ; PAGE 1
        LDA $FBB3
        CMP #$38        ; APPLE ][
        BEQ UPPER
        CMP #$EA        ; APPLE ][+
        BEQ UPPER
        LDA $FBC0
        CMP #$EA        ; APPLE //e
        BEQ UPPER
        LDA $C01E       ; CHARSET?
        PHA
        STA $C00F       ; ALT CHARSET
        LDA $C01F       ; COLS?
        PHA
        STA $C00C       ; 40 COLS
        LDA #$66        ; LOWERCASE
        PHP
        BNE LOOP        ; ALWAYS
UPPER: PHP
        LDA #$65        ; UPPERCASE

LOOP: STA DATA
        LDA #$40        ; CONFIG
        JSR WRCMD
        BNE SCRN        ; QUIT?

        PLP
        BEQ NOCHAR
        PLA             ; COLS
        BPL NOCOLS      ; 40 COLS?
        STA $C00D       ; 80 COLS
NOCOLS: PLA             ; CHARSET
        BMI NOCHAR      ; ALT CHARSET?
        STA $C00E       ; PRI CHARSET
NOCHAR: JSR HOME
        RTS

SCRN: LDX #$00
LINE: TXA
        JSR BASCALC
        LDY #$00
CHAR: LDA DATA
        STA (BASL),Y
        INY
        CPY #$28        ; COLS
        BCC CHAR
        INX
        CPX #$18        ; ROWS
        BCC LINE

GETKEY: LDA KBD
        BPL GETKEY
        STA KBDSTRB
        BMI LOOP

        .res $CF00-*

